// GenerateAuthURL generates an OAuth2 authorization URL for the user to authenticate.
// The redirectPath parameter allows customization of where the user should be redirected after auth.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Validate the redirectPath to prevent open redirect vulnerabilities
	if !isValidRedirectURL(redirectPath, r.Host) {
		return "", fmt.Errorf("invalid redirect URL")
	}

	state := generateSecureState()

	// Create a copy of the OAuth config with the custom redirect URL
	config := *OAuthConfig
	config.RedirectURL = redirectPath

	// Generate the authorization URL
	authURL := config.AuthCodeURL(state)

	// Set the state in a cookie for later validation
	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteLaxMode,
		Path:     "/",
	})

	return authURL, nil
}

// generateSecureState generates a random, unpredictable state value for OAuth flow
func generateSecureState() string {
	b := make([]byte, 32)
	rand.Read(b)
	return fmt.Sprintf("%x", b)
}

// isValidRedirectURL checks if the provided redirect URL is valid
// It ensures the URL is properly formatted and points to a trusted domain
func isValidRedirectURL(redirectURL, host string) bool {
	if redirectURL == "" {
		return false
	}

	parsedURL, err := url.ParseRequestURI(redirectURL)
	if err != nil {
		return false
	}

	// Check if the scheme is either http or https
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return false
	}

	// If it's an absolute URL, check that it matches our host (for security)
	if parsedURL.Host != "" {
		// Allow URLs that match the current host
		if strings.EqualFold(parsedURL.Host, host) {
			return true
		}
		// Add any other trusted domains here if needed
		return false
	}

	// For relative paths, ensure they start with / and don't contain .. to prevent directory traversal
	if !strings.HasPrefix(redirectURL, "/") || strings.Contains(redirectURL, "../") {
		return false
	}

	return true
}

// GetOAuthConfig returns a copy of the OAuth config to allow external access
func GetOAuthConfig() *oauth2.Config {
	config := *OAuthConfig
	return &config
}

