}

// isValidRedirectURL validates that the redirect URL is safe to use
func isValidRedirectURL(redirectURL string) bool {
	if redirectURL == "" {
		return false
	}

	parsedURL, err := url.Parse(redirectURL)
	if err != nil {
		return false
	}

	// Only allow HTTPS URLs to prevent downgrade attacks
	if parsedURL.Scheme != "https" {
		return false
	}

	// Prevent open redirect by ensuring the host matches expected patterns
	// In a real application, you would have a whitelist of allowed domains
	allowedDomains := []string{"yourapp.com"} // Replace with your actual domain(s)
	isAllowedDomain := false
	for _, domain := range allowedDomains {
		if strings.HasSuffix(parsedURL.Hostname(), domain) {
			isAllowedDomain = true
			break
		}
	}

	return isAllowedDomain
}

// generateSecureState creates a cryptographically secure random state value
func generateSecureState() (string, error) {
	b := make([]byte, 32)
	_, err := rand.Read(b)
	if err != nil {
		return "", err
	}

	// Convert bytes to hex string representation
	state := fmt.Sprintf("%x", b)
	return state, nil
