}

// isValidRedirectPath validates that the redirect path is safe to use
// It checks if the redirectPath is either a relative path or has the same host as the request
func isValidRedirectPath(redirectPath, host string) bool {
	// Check if it's a relative path (doesn't contain :// which indicates a scheme)
	if !strings.Contains(redirectPath, "://") {
		// For relative paths, ensure they start with / and don't have dangerous patterns
