	// This prevents open redirect to arbitrary domains
	return parsedURL.Host == host
}

// hasDangerousPathTraversal checks if the path contains potentially dangerous traversal sequences
func hasDangerousPathTraversal(path string) bool {
	return strings.Contains(path, "../") || strings.Contains(path, "..\\")
