func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Validate the redirectPath to ensure it's a safe URL
	if !isValidRedirectURL(redirectPath) {
		return "", fmt.Errorf("invalid redirect URL provided")
	}

	state, err := generateRandomState()
	if err != nil {
		return "", fmt.Errorf("failed to generate state: %w", err)
	}

	// Create a copy of the OAuth config with the custom redirect URL
	config := *OAuthConfig
	config.RedirectURL = redirectPath

	// Generate the authorization URL
	authURL := config.AuthCodeURL(state)

	// Set the state in a cookie for later validation
	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteLaxMode,
		Path:     "/",
	})

	return authURL, nil
}

// generateRandomState generates a random state string for CSRF protection
func generateRandomState() (string, error) {
	b := make([]byte, 32)
	if _, err := rand.Read(b); err != nil {
		return "", err
	}

	// Convert to hexadecimal string for URL safety
	state := fmt.Sprintf("%x", b)
	return state, nil
}

// isValidRedirectURL checks if the provided redirect URL is valid and safe
func isValidRedirectURL(redirectURL string) bool {
	if redirectURL == "" {
		return false
	}

	parsedURL, err := url.Parse(redirectURL)
	if err != nil {
		return false
	}

	// Check if the scheme is either http or https
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return false
	}

	// Prevent open redirect by ensuring the URL doesn't contain unexpected patterns
	if strings.Contains(redirectURL, "..") || strings.Contains(redirectURL, ":\\") {
		return false
	}

	// Check if the host is not empty for absolute URLs
	if parsedURL.IsAbs() && parsedURL.Host == "" {
		return false
	}

	// Allow relative URLs (no scheme/host) to pass through
	if !parsedURL.IsAbs() {
		return true
	}

	return true
}

// containsDomain checks if the given hostname matches any of the allowed domains
func containsDomain(domains []string, hostname string) bool {
	for _, domain := range domains {
		if domain == hostname {
			return true
		}
		// Check for subdomains too
		if strings.HasSuffix(hostname, "."+domain) {
			return true
		}
	}
	return false
}

