// The redirectPath parameter allows customization of where the user should be redirected after auth.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// If redirectPath is empty, use default redirect URL from config
	var finalRedirectPath string
	if redirectPath == "" {
		finalRedirectPath = OAuthConfig.RedirectURL
	} else {
		// Validate the redirect path to prevent open redirect vulnerabilities
		if !isValidRedirectPath(redirectPath) {
			return "", fmt.Errorf("invalid redirect path")
		}
		finalRedirectPath = redirectPath
	}

	state := generateRandomState()

	// Create a copy of the OAuth config with the custom redirect URL
	config := *OAuthConfig
	config.RedirectURL = finalRedirectPath

	// Generate the authorization URL
	authURL := config.AuthCodeURL(state)

	// Set the state in a cookie for later validation
	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteLaxMode,
		Path:     "/",
	})

	return authURL, nil
}

// generateRandomState creates a cryptographically secure random state string
func generateRandomState() string {
	const charset = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789"
	const length = 32

	result := make([]byte, length)
	for i := range result {
		num, _ := rand.Int(rand.Reader, big.NewInt(int64(len(charset))))
		result[i] = charset[num.Int64()]
	}
	return string(result)
}

// isValidRedirectPath checks if the redirect path is valid to prevent open redirect vulnerabilities
func isValidRedirectPath(redirectPath string) bool {
	if redirectPath == "" {
		return false
	}

	// Parse the URL to extract components
	parsedURL, err := url.ParseRequestURI(redirectPath)
	if err != nil {
		return false
	}

	// Ensure it's using https scheme
	if parsedURL.Scheme != "https" {
		return false
	}

	// Define allowed domains for redirect
	allowedDomains := []string{
		"yourapp.com",
		// Add other trusted domains here if needed
	}

